import json

todos = [{"id": 1, "text": "Learn Python", "done": False}]

def add_task(text):
    todos.append({"id": len(todos)+1, "text": text, "done": False})

def list_tasks():
    for t in todos:
        mark = "x" if t["done"] else " "
        print(f"[{mark}] {t["text"]}")

add_task("Build project")
list_tasks()

contacts = {}

def add_contact(name, phone, email):
    contacts[name.lower()] = {"phone": phone, "email": email}

def find(name):
    return contacts.get(name.lower())

add_contact("Ana", "555-0100", "ana@mail.com")
print(find("ana"))
